INSERT INTO `problems` VALUES (1,'Two Sum','two-sum','[\"a\", \"b\"]','<p>&nbsp;</p>\n<p>\nGiven an array of integers nums and an integer target, return indices of the two numbers such that they add up to target.\n</p>\n<p>&nbsp;</p>\n<p>\nYou may assume that each input would have exactly one solution, and you may not use the same element twice.\n</p>\n<p>&nbsp;</p>\n<p>\nYou can return the answer in any order.\n</p>\n<p>&nbsp;</p>\n    \n<div>\n        <strong>Example 1:</strong>\n\n        <pre style=\"white-space: pre-wrap;\">\n<strong>Input:</strong> nums = [2,7,11,15], target = 9\n<strong>Output:</strong> [0,1]\n<strong>Explanation:</strong> Because nums[0] + nums[1] == 9, we return [0, 1].\n        </pre>\n</div>\n\n<div>\n        <strong>Example 1:</strong>\n\n        <pre style=\"white-space: pre-wrap;\">\n<strong>Input:</strong> nums = [2,7,11,15], target = 9\n<strong>Output:</strong> [0,1]\n<strong>Explanation:</strong> Because nums[0] + nums[1] == 9, we return [0, 1].\n        </pre>\n</div>','def add(a: int, b: int):\n return a + b;','import heapq\nfrom collections import deque\n','import sys\nimport io\nimport json\n\ndef solution(a, b):\n    return a + b\n\ndef run_testcase(func, a, b):\n    old_stdout = sys.stdout\n    sys.stdout = buffer = io.StringIO()\n    try:\n        got = func(a, b)\n        printed = buffer.getvalue()\n    finally:\n        sys.stdout = old_stdout\n    return {\"args\": [a,b], \"got\": got, \"expected\": solution(a, b), \"printed\": printed}\n\ndef main():\n    t = json.loads(input())\n    for _ in range(t):\n        a = json.loads(input())\n        b = json.loads(input())\n        res = run_testcase(add, a, b)\n        if res[\"got\"] != res[\"expected\"]:\n            output = {\"status\": \"Wrong Answer\", \"testcase\": res}\n            print(json.dumps(output))\n            return\n    print(json.dumps({\"status\": \"Accepted\"}))\n\nif __name__ == \"__main__\":\n    main()','1\n0\n1\n1\n1\n2','1\n0\n1\n0\n1\n0',2000,'Medium'),(2,'Sum of All Nodes','sum-of-all-nodes','[\"nodes\", \"edges\"]','<p>\nGiven an array <code>nodes</code> of size <code>n</code> and array <code>edges</code>. <code>nodes[i]</code> is the value of vertex <code>i</code>. In <code>edges[i]</code> each element <code>[u, v]</code>  represents an undirected edge between vertex u and vertex v. Return sum of nodes of each component.\n</p>\n<p>&nbsp;</p>\n<div>\n        <strong>Example 1:</strong>\n\n<pre class=\"example-block\">\n<strong>Input:</strong> nodes = [1, 2, 3, 4, 5], edges = [[0,1],[0,2],[3,4]]\n\n<strong>Output:</strong> [6,6,6,9,9]\n\n<strong>Explanation:</strong> \nNodes 0,1,2 form a connected component: sum = 1+2+3 = 6\nNodes 3,4 form a connected component: sum = 4+5 = 9\nResult = [6,6,6,9,9]\n</pre>\n</div>\n<p>&nbsp;</p>\n<div>\n        <strong>Constraints:</strong>\n  <div class=\"constraints\">\n   <ul>\n     <li><code>1 <= n <= 10^5</code></li>\n     <li><code>0 <= len(edges) <= 2*10^5</code></li>\n     <li><code>1 <= nodes[i] <= 10^9</code></li>\n     <li><code>0 <= u, v < n</code></li>\n     <li><code>u != v</code></li>\n     <li>No duplicate edges</li>\n   </ul>\n  </div>\n</div>','def sum_of_all_nodes(nodes: List[int], edges: List[List[int]]) -> List[int]:\n  n = len(nodes)\n  graph = defaultdict(list)\n  for u, v in edges:\n      graph[u].append(v)\n      graph[v].append(u)\n  visited = [False] * n\n  result = [0] * n\n\n  def dfs(node, component):\n      visited[node] = True\n      component.append(node)\n      for neighbor in graph[node]:\n          if not visited[neighbor]:\n              dfs(neighbor, component)\n\n  for i in range(n):\n      if not visited[i]:\n          component = []\n          dfs(i, component)\n          total = sum(nodes[x] for x in component)\n          for x in component:\n              result[x] = total\n\n  return result','import heapq\nfrom collections import deque, defaultdict\nfrom typing import List','import sys\nimport io\nimport json\nfrom typing import List\nfrom collections import defaultdict\n\ndef solution(nodes: List[int], edges: List[List[int]]) -> List[int]:\n    n = len(nodes)\n    graph = defaultdict(list)\n    for u, v in edges:\n        graph[u].append(v)\n        graph[v].append(u)\n    visited = [False] * n\n    result = [0] * n\n\n    def dfs(node, component):\n        visited[node] = True\n        component.append(node)\n        for neighbor in graph[node]:\n            if not visited[neighbor]:\n                dfs(neighbor, component)\n\n    for i in range(n):\n        if not visited[i]:\n            component = []\n            dfs(i, component)\n            total = sum(nodes[x] for x in component)\n            for x in component:\n                result[x] = total\n\n    return result\n\ndef run_testcase(func, a, b):\n    old_stdout = sys.stdout\n    sys.stdout = buffer = io.StringIO()\n    try:\n        got = func(a, b)\n        printed = buffer.getvalue()\n    finally:\n        sys.stdout = old_stdout\n    return {\"args\": [a,b], \"got\": got, \"expected\": solution(a, b), \"printed\": printed}\n\ndef main():\n    t = json.loads(input())\n    for _ in range(t):\n        a = json.loads(input())\n        b = json.loads(input())\n        res = run_testcase(sum_of_all_nodes, a, b)\n        if res[\"got\"] != res[\"expected\"]:\n            output = {\"status\": \"Wrong Answer\", \"testcase\": res}\n            print(json.dumps(output))\n            return\n    print(json.dumps({\"status\": \"Accepted\"}))\n\nif __name__ == \"__main__\":\n    main()','[1,2,3,4,5]\n[[0,1],[0,2],[3,4]]','[1,2,3,4,5]\n[[0,1],[0,2],[3,4]]\n[1,2]\n[[0,1]]',2000,'Easy');
