INSERT INTO `visualizations` VALUES (1,'DFS','dfs','async function algorithm(\n{\n	graphRef,\n	tutorialRef,\n	waitOnClick,\n  	nodes,\n  	edges,\n	adjacency,\n  	selectedNode\n}\n) {\n\n  for (const [source, neighbours] of Object.entries(adjacency)) {\n    adjacency[source] = neighbours.map((val) => val.nodeId);\n  }\n\n  const visitedEdges = {};\n\n  for (const node of nodes) {\n    visitedEdges[node.id] = {};\n  }\n  \n  async function dfs(node, visited = new Set(), parent) {\n    visited.add(node);\n\n    graphRef.current?.markNode({ nodeId: node });\n\n    if (visited.size === 1)\n      tutorialRef.current?.addTutorialStep({\n        description: `Let\'s begin exploring from Node ${node}`,\n        node: { nodeId: node },\n        variables: {\n          visited: Array.from(visited),\n          neighbours: adjacency[node],\n          node,\n        },\n      });\n    else\n      tutorialRef.current?.addTutorialStep({\n        description: `Exploring Node ${node}`,\n        node: { nodeId: node },\n        variables: {\n          visited: Array.from(visited),\n          neighbours: adjacency[node],\n          node,\n        },\n      });\n\n    await waitOnClick();\n\n    for (const neighbor of adjacency[node]) {\n      if (visited.has(neighbor)) {\n        if (\n          !visitedEdges[node][neighbor] &&\n          !visitedEdges[neighbor][node]\n        ) {\n          graphRef.current?.markEdge({\n            sourceId: node,\n            destinationId: neighbor,\n            directed: false,\n            edgeColor: \"gray\",\n          });\n\n          tutorialRef.current?.addTutorialStep({\n            description: `Edge ${node} -- ${neighbor}: Node ${neighbor} has already been visited! We\'ll mark this path gray to show it\'s been checked.`,\n            variables: {\n              visited: Array.from(visited),\n              neighbours: adjacency[node],\n              node,\n            },\n            edge: {\n              sourceId: node,\n              destinationId: neighbor,\n              directed: false,\n              edgeColor: \"gray\",\n            },\n          });\n\n          visitedEdges[node][neighbor] = true;\n          visitedEdges[neighbor][node] = true;\n\n          await waitOnClick();\n        } else {\n          tutorialRef.current?.addTutorialStep({\n            description: `Edge ${node} -- ${neighbor}: We\'ve already used this path! Skipping it to avoid going in circles.`,\n            variables: {\n              visited: Array.from(visited),\n              neighbours: adjacency[node],\n              node,\n            },\n          });\n\n          await waitOnClick();\n        }\n      } else {\n        tutorialRef.current?.addTutorialStep({\n          description: `Edge ${node} -- ${neighbor}: Let’s head to ${neighbor} since it\'s unexplored! This becomes a new branch in our DFS tree.`,\n          variables: {\n            visited: Array.from(visited),\n            neighbours: adjacency[node],\n            node,\n          },\n        });\n\n        await waitOnClick();\n\n        visitedEdges[node][neighbor] = true;\n        visitedEdges[neighbor][node] = true;\n\n        graphRef.current?.markEdge({\n          sourceId: node,\n          destinationId: neighbor,\n          directed: false,\n        });\n        tutorialRef.current?.addTutorialStep({\n          edge: { sourceId: node, destinationId: neighbor, directed: false },\n          isStep: false,\n        });\n\n        await dfs(neighbor, visited, node);\n      }\n    }\n   		 \n    if(parent !== undefined) {\n	    tutorialRef.current?.addTutorialStep({\n      		description: `No more unexplored tunnels here! Let\'s follow our string back from ${node} to ${parent} and look for another way.`,\n      		variables: {\n        		visited: Array.from(visited),\n        		neighbours: adjacency[node],\n        		node,\n      		},\n    	});\n      \n      await waitOnClick();\n    }\n  }\n\n  await dfs(selectedNode)\n}\n\nreturn algorithm','{\"variables\": {\"node\": \"\", \"visited\": [], \"neighbours\": []}, \"buttonText\": \"Start\", \"description\": \"DFS (Depth-First Search) is like exploring a mysterious cave with a ball of string. You pick one tunnel and follow it as deep as you can, marking each cavern with chalk so you never visit the same room twice. If you hit a dead end, just follow your string back to the last opening and try a different path until the whole cave is discovered!\"}','procedure DFS(node):\n  visited.add(node)\n  for each neighbour in neighbours(node):\n    if neighbour not in visited:\n      DFS(neighbour)','[{\"id\": \"1\"}, {\"id\": \"2\"}, {\"id\": \"3\"}, {\"id\": \"4\"}, {\"id\": \"5\"}, {\"id\": \"6\"}]','[{\"source\": {\"id\": \"2\"}, \"target\": {\"id\": \"1\"}}, {\"source\": {\"id\": \"1\"}, \"target\": {\"id\": \"3\"}}, {\"source\": {\"id\": \"2\"}, \"target\": {\"id\": \"4\"}}, {\"source\": {\"id\": \"3\"}, \"target\": {\"id\": \"5\"}}, {\"source\": {\"id\": \"5\"}, \"target\": {\"id\": \"6\"}}, {\"source\": {\"id\": \"2\"}, \"target\": {\"id\": \"5\"}}]','function reset({graphRef, tutorialRef}) {\n\n}\n\nreturn reset',_binary '',''),(2,'BFS','bfs','async function algorithm(\n{\n	graphRef,\n	tutorialRef,\n	waitOnClick,\n  	nodes,\n  	edges,\n	adjacency,\n  	selectedNode\n}\n) {  \n\n  for (const [source, neighbours] of Object.entries(adjacency)) {\n    adjacency[source] = neighbours.map((val) => val.nodeId);\n  }\n\n  async function bfs(startId, visited = new Set()) {\n      const queue = [startId];\n      visited.add(startId);\n\n      const prevNodes = {};\n\n      tutorialRef.current?.addTutorialStep({\n        description: `Let\'s place our lantern at Node ${startId} and add it to our search list to begin the journey!`,\n        variables: {\n          queue: Array.from(queue),\n          node: startId,\n        },\n      });\n\n      await waitOnClick();\n\n      while (queue.length > 0) {\n        const node = queue.shift() ?? \"\";\n\n        graphRef.current?.markNode({ nodeId: node });\n\n        const prevNode = prevNodes[node];\n\n        if (prevNode) {\n          graphRef.current?.markEdge({\n            sourceId: prevNode,\n            destinationId: node,\n	    directed: false,\n          });\n        }\n\n        tutorialRef.current?.addTutorialStep({\n          description: `Now, we pick the first node from our list (Node ${node}) and step into the light to see who its neighbors are!`,\n          node: { nodeId: node },\n          variables: {\n            queue: Array.from(queue),\n            node,\n          },\n          edge: prevNode\n            ? { sourceId: prevNode, destinationId: node }\n            : undefined,\n        });\n\n        await waitOnClick();\n\n        const addedNeighbours = [];\n\n        for (const neighbor of adjacency[node]) {\n          if (!visited.has(neighbor)) {\n            visited.add(neighbor);\n            queue.push(neighbor);\n            prevNodes[neighbor] = node;\n\n            addedNeighbours.push(neighbor);\n          }\n        }\n\n        if (addedNeighbours.length) {\n          tutorialRef.current?.addTutorialStep({\n            description: `The light from Node ${node} sparks out to its new neighbors! We\'re adding ${addedNeighbours} to our list to explore them next.`,\n            variables: {\n              queue: Array.from(queue),\n              node,\n            },\n          });\n\n          await waitOnClick();\n        }\n      }\n\n      tutorialRef.current?.addTutorialStep({\n        description: `The light has reached everywhere! All nodes have been discovered and added to our search, so our journey is complete.`,\n        buttonText: \"Restart\",\n      });\n       await waitOnClick();\n\n      const buttonClickHandler = () => {\n        tutorialRef.current?.resetTutorialSteps();\n        graphRef.current?.resetMarks();\n\n        tutorialRef.current?.addTutorialStep(initialStep);\n\n        const nextButtonClickHandler = () => {\n          bfs(initialNode);\n        };\n\n        tutorialRef.current?.setNextButtonOnceClickHanlder(\n          nextButtonClickHandler,\n        );\n      };\n\n      tutorialRef.current?.setNextButtonOnceClickHanlder(buttonClickHandler);\n    }\n  \n    await bfs(selectedNode)\n}\n\nreturn algorithm','{\"variables\": {\"node\": \"\", \"queue\": []}, \"buttonText\": \"Start\", \"description\": \"BFS (Breadth-First Search) is like turning on a lantern in a dark room. Instead of pointing a tiny laser deep into one corner, the light shines everywhere nearby at the same time. You start at your first node and visit all of its immediate neighbors, giving them a bright glow so you know they\'ve been reached. Once you\'ve lit up everything one step away, the light naturally pushes further out to the next circle of nodes. By exploring layer by layer, you\'re guaranteed to find the closest path to any node in the graph!\"}','procedure BFS(start):\n  visited <- new Set()\n  queue <- new Queue()\n\n  queue.enqueue(start)\n  visited.add(start)\n\n  while not queue.isEmpty():\n    node <- queue.dequeue()\n\n    for each neighbour in neighbours(node):\n      if neighbour not in visited:\n        visited.add(neighbour)\n        queue.enqueue(neighbour)','[{\"id\": \"1\"}, {\"id\": \"2\"}, {\"id\": \"3\"}, {\"id\": \"4\"}, {\"id\": \"5\"}, {\"id\": \"6\"}]','[{\"source\": {\"id\": \"1\"}, \"target\": {\"id\": \"2\"}}, {\"source\": {\"id\": \"1\"}, \"target\": {\"id\": \"3\"}}, {\"source\": {\"id\": \"2\"}, \"target\": {\"id\": \"4\"}}, {\"source\": {\"id\": \"3\"}, \"target\": {\"id\": \"5\"}}, {\"source\": {\"id\": \"5\"}, \"target\": {\"id\": \"6\"}}]','function reset({graphRef, tutorialRef}) {\n\n}\n\nreturn reset',_binary '',''),(3,'Dijkstra Algorithm - Shortest Path','dijkstra','async function algorithm({\n  graphRef,\n  tutorialRef,\n  waitOnClick,\n  nodes,\n  edges,\n  adjacency,\n  selectedNode\n}) {\n  const toNumber = (str) => (isNaN(Number(str)) ? 0 : Number(str));\n\n  async function dijkstra(node) {\n    const minQ = new this.MinPriorityQueue((item) => toNumber(item.weight));\n    const visited = new Set();\n\n    minQ.enqueue({ nodeId: node, weight: \"0\" });\n\n    tutorialRef.current?.addTutorialStep({\n      description: `Setting Node ${node} as our starting point! We\'re adding it to our priority list to begin mapping out the fastest routes to everywhere else.`,\n      node: { nodeId: node },\n      variables: {\n        queue: minQ.toArray(),\n        visited: Array.from(visited),\n        neighbours: adjacency[node].map((node) => node.nodeId),\n        node,\n      },\n    });\n    await waitOnClick();\n\n    while (!minQ.isEmpty()) {\n      const minNode = minQ.dequeue();\n\n      if (!minNode) continue;\n\n      if (visited.has(minNode.nodeId)) {\n        tutorialRef.current?.addTutorialStep({\n          description: `We picked Node ${minNode.nodeId} from the list, but we\'ve already found the fastest way there! Skipping it to stay on track and keep our map accurate.`,\n          variables: {\n            queue: minQ.toArray(),\n            visited: Array.from(visited),\n            neighbours: adjacency[minNode.nodeId].map((node) => node.nodeId),\n            node: minNode.nodeId,\n          },\n        });\n\n        await waitOnClick();\n\n        continue;\n      }\n\n      visited.add(minNode.nodeId);\n      graphRef.current?.markNode({ nodeId: minNode.nodeId });\n\n      tutorialRef.current?.addTutorialStep({\n        description: `We\'re picking the quickest path from our list! Currently, that\'s Node ${minNode.nodeId} with a total travel time of ${minNode.weight}. Let\'s see where we can go from here.`,\n        node: { nodeId: minNode.nodeId },\n        variables: {\n          queue: minQ.toArray(),\n          visited: Array.from(visited),\n          neighbours: adjacency[minNode.nodeId].map((node) => node.nodeId),\n          node: minNode.nodeId,\n        },\n      });\n\n      await waitOnClick();\n\n      for (const nextNode of adjacency[minNode.nodeId]) {\n        if (visited.has(nextNode.nodeId)) {\n          tutorialRef.current?.addTutorialStep({\n            description: `Path ${minNode.nodeId} -- ${nextNode.nodeId}: We’ve already found the fastest way to Node ${nextNode.nodeId}! Skipping this edge to keep our map accurate and avoid extra steps.`,\n            variables: {\n              queue: minQ.toArray(),\n              visited: Array.from(visited),\n              neighbours: adjacency[minNode.nodeId].map((node) => node.nodeId),\n              node: minNode.nodeId,\n            },\n          });\n\n          await waitOnClick();\n\n          continue;\n        }\n\n        minQ.enqueue({\n          nodeId: nextNode.nodeId,\n          weight: (\n            toNumber(nextNode.weight) + toNumber(minNode.weight)\n          ).toString(),\n        });\n\n        graphRef.current?.markEdge({\n          sourceId: minNode.nodeId,\n          destinationId: nextNode.nodeId,\n          directed: true,\n        });\n        tutorialRef.current?.addTutorialStep({\n          description: `Edge ${minNode.nodeId} -- ${nextNode.nodeId}: We’ve discovered a way to reach Node ${nextNode.nodeId}! We’re adding it to our list with a total travel time of ${totalWeight} to explore it later.`,\n          variables: {\n            queue: minQ.toArray(),\n            visited: Array.from(visited),\n            neighbours: adjacency[minNode.nodeId].map((node) => node.nodeId),\n            node: minNode.nodeId,\n          },\n          edge: {\n            sourceId: minNode.nodeId,\n            destinationId: nextNode.nodeId,\n            directed: true,\n          },\n        });\n\n        await waitOnClick();\n      }\n    }\n  }\n\n  await dijkstra.bind(this)(selectedNode);\n}\n\nreturn algorithm;','{\"variables\": {\"node\": \"\", \"queue\": [], \"visited\": [], \"neighbours\": []}, \"buttonText\": \"Start\", \"description\": \"Dijkstra\'s Algorithm is like a smart GPS finding the fastest route to every point. You start at your home node and always pick the shortest path available on your list. Every time you reach a new spot, you check if you\'ve found a faster shortcut to the nodes around it. By always taking the quickest step first, you eventually map out the absolute best way to reach every single destination!\"}','procedure Dijkstra(startNode):\n  for each vertex v in Graph:\n    distance[v] <- ∞\n    previous[v] <- undefined\n  distance[startNode] <- 0\n\n  priorityQueue <- empty min-priority queue\n  priorityQueue.insert(startNode, 0)\n\n  while priorityQueue is not empty:\n    node <- priorityQueue.extractMin()\n\n    if node is already visited:\n      continue\n\n    mark node as visited\n\n    for each neighbour in neighbours(node):\n      newDistance <- distance[node] + weight(node, neighbour)\n      if newDistance < distance[neighbour]:\n        distance[neighbour] <- newDistance\n        previous[neighbour] <- node\n        priorityQueue.insert(neighbour, newDistance)','[{\"id\": \"1\"}, {\"id\": \"2\"}, {\"id\": \"3\"}, {\"id\": \"4\"}, {\"id\": \"5\"}, {\"id\": \"6\"}]','[{\"source\": {\"id\": \"1\"}, \"target\": {\"id\": \"2\"}, \"weight\": \"6\", \"directed\": true}, {\"source\": {\"id\": \"1\"}, \"target\": {\"id\": \"3\"}, \"weight\": \"3\", \"directed\": true}, {\"source\": {\"id\": \"2\"}, \"target\": {\"id\": \"4\"}, \"weight\": \"1\", \"directed\": true}, {\"source\": {\"id\": \"3\"}, \"target\": {\"id\": \"5\"}, \"weight\": \"8\", \"directed\": true}, {\"source\": {\"id\": \"5\"}, \"target\": {\"id\": \"6\"}, \"weight\": \"5\", \"directed\": true}, {\"source\": {\"id\": \"2\"}, \"target\": {\"id\": \"5\"}, \"weight\": \"2\", \"directed\": true}]','function reset({graphRef, tutorialRef}) {\n\n}\n\nreturn reset',_binary '',''),(4,'Euler Path - Undirected Graph','euler-path-undirected','async function algorithm({\n  graphRef,\n  tutorialRef,\n  waitOnClick,\n  nodes,\n  edges,\n  adjacency,\n  selectedNode,\n}) {\n  \n  visitedEdges = {}\n\n  async function eulerianPath(node, path = []) {\n    const neighbours = adjacency[node];\n\n    for (const neighbor of neighbours) {\n      if (!visitedEdges[node]) visitedEdges[node] = {};\n      if (!visitedEdges[neighbor.nodeId]) visitedEdges[neighbor.nodeId] = {};\n\n      if (visitedEdges[node][neighbor.nodeId]) continue;\n\n      visitedEdges[node][neighbor.nodeId] = true;\n      visitedEdges[neighbor.nodeId][node] = true;\n\n      graphRef.current?.markEdge({\n        sourceId: node,\n        destinationId: neighbor?.nodeId ?? \"\",\n	directed: false,\n      });\n      tutorialRef.current?.addTutorialStep({\n        description: `We just crossed the bridge ${node} -- ${neighbor?.nodeId}! We’re coloring this line in so we know it’s already been used and we can’t cross it again.`,\n        edge: { sourceId: node, destinationId: neighbor?.nodeId ?? \"\" },\n        variables: {\n          path: [...path],\n          neighbours: neighbours.map((neighbour) => neighbour.nodeId),\n          node: node,\n        },\n      });\n\n      await waitOnClick();\n\n      await eulerianPath(neighbor?.nodeId ?? \"\", path);\n    }\n\n    path.push(node);\n    graphRef.current?.markNode({ nodeId: node });\n    tutorialRef.current?.addTutorialStep({\n      description: `We’ve hit a dead end at Node ${node}! Since there are no more bridges to cross from here, we’re officially adding this node to our final trail and backtracking to find any missed paths.`,\n      node: { nodeId: node },\n      variables: {\n        path: [...path],\n        neighbours: neighbours.map((neighbour) => neighbour.nodeId),\n        node: node,\n      },\n    });\n\n    await waitOnClick();\n  }\n\n  await eulerianPath(selectedNode);\n}\n\nreturn algorithm;','{\"variables\": {\"node\": \"\", \"path\": [], \"neighbours\": []}, \"buttonText\": \"Start\", \"description\": \"Euler\'s Path and Cycle are like a drawing challenge: can you trace every single line in a sketch without lifting your pen or going over the same line twice? You must cross every bridge (edge) exactly once. A path lets you start at one spot and finish somewhere else, while a cycle is the ultimate loop - you end up right back where you started!\"}','procedure EulerPath(V)\n    for each edge (V, U) in Graph:\n        remove edge (V, U) from Graph\n        remove edge (U, V) from Graph\n        EulerPath(U)\n    add V to path','[{\"id\": \"1\"}, {\"id\": \"2\"}, {\"id\": \"3\"}, {\"id\": \"4\"}, {\"id\": \"5\"}, {\"id\": \"6\"}]','[{\"source\": {\"id\": \"1\"}, \"target\": {\"id\": \"3\"}}, {\"source\": {\"id\": \"3\"}, \"target\": {\"id\": \"5\"}}, {\"source\": {\"id\": \"5\"}, \"target\": {\"id\": \"6\"}}, {\"source\": {\"id\": \"2\"}, \"target\": {\"id\": \"1\"}}, {\"source\": {\"id\": \"6\"}, \"target\": {\"id\": \"4\"}}, {\"source\": {\"id\": \"4\"}, \"target\": {\"id\": \"2\"}}]','function reset({graphRef, tutorialRef}) {\n      \n}\n\nreturn reset',_binary '','<p><strong>Selecting the Starting Vertex for Euler Path</strong></p>\nIn the algorithm for finding an Eulerian Path, starting from the correct vertex is crucial. For an undirected graph, the rules are as follows:\n<ul style=\"list-style-type: disc; padding-left: 1em;\">\n<li style=\"margin: 1em 0;\">\nIf all vertices have an even degree (an even number of edges), the algorithm can start from <strong>any vertex</strong>.\n</li>\n<li style=\"margin: 1em 0;\">\nIf there are exactly two vertices with an odd degree, the algorithm must start from <strong>one of those two vertices</strong>.\n</li>\n</ul>'),(5,'Euler Path - Directed Graph','euler-path-directed','async function algorithm({\n  graphRef,\n  tutorialRef,\n  waitOnClick,\n  nodes,\n  edges,\n  adjacency,\n  selectedNode,\n}) {\n  async function eulerianPath(node, path = []) {\n    const neighbours = adjacency[node];\n\n    while (neighbours.length) {\n      const neighbor = neighbours.pop();\n\n      graphRef.current?.markEdge({\n        sourceId: node,\n        destinationId: neighbor?.nodeId ?? \"\",\n      });\n      tutorialRef.current?.addTutorialStep({\n        description: `We’re following the arrow from Node ${node} to Node ${neighbor?.nodeId}. This one-way street is now closed because we\'ve already driven through it - we can\'t go back!`,\n        edge: { sourceId: node, destinationId: neighbor?.nodeId ?? \"\" },\n        variables: {\n          path: [...path],\n          neighbours: neighbours.map((neighbour) => neighbour.nodeId),\n          node: node,\n        },\n      });\n      await waitOnClick();\n\n      await eulerianPath(neighbor?.nodeId ?? \"\", path);\n    }\n\n    path.push(node);\n    graphRef.current?.markNode({ nodeId: node });\n    tutorialRef.current?.addTutorialStep({\n      description: `We\'ve reached Node ${node} and there are no more arrows leading out. Since we\'re at a dead end, we\'re adding this spot to our final route and backtracking to see if we missed any other streets.`,\n      node: { nodeId: node },\n      variables: {\n        path: [...path],\n        neighbours: neighbours.map((neighbour) => neighbour.nodeId),\n        node: node,\n      },\n    });\n\n    await waitOnClick();\n  }\n\n  await eulerianPath(selectedNode);\n}\n\nreturn algorithm;','{\"variables\": {\"node\": \"\", \"path\": [], \"neighbours\": []}, \"buttonText\": \"Start\", \"description\": \"Euler\'s Path and Cycle in a directed graph is like a GPS challenge where every road is a one-way street. Your goal is to drive through every single street exactly once. A Path is a journey where you start at one point and finish at another. A Cycle is the perfect loop - you follow the arrows and end up exactly where you started.\"}','procedure EulerPath(V)\n    for each edge (V, U) in Graph:\n        remove edge (V, U) from Graph\n        EulerPath(U)\n    add V to path','[{\"id\": \"1\"}, {\"id\": \"2\"}, {\"id\": \"3\"}, {\"id\": \"4\"}, {\"id\": \"5\"}, {\"id\": \"6\"}]','[{\"source\": {\"id\": \"1\"}, \"target\": {\"id\": \"3\"}, \"directed\": true}, {\"source\": {\"id\": \"3\"}, \"target\": {\"id\": \"5\"}, \"directed\": true}, {\"source\": {\"id\": \"5\"}, \"target\": {\"id\": \"6\"}, \"directed\": true}, {\"source\": {\"id\": \"2\"}, \"target\": {\"id\": \"1\"}, \"directed\": true}, {\"source\": {\"id\": \"6\"}, \"target\": {\"id\": \"4\"}, \"directed\": true}, {\"source\": {\"id\": \"4\"}, \"target\": {\"id\": \"2\"}, \"directed\": true}]','function reset({graphRef, tutorialRef}) {\n      \n}\n\nreturn reset',_binary '','<p><strong>Selecting the Starting Vertex for Euler Path</strong></p>\nIn the algorithm for finding an Eulerian Path in a directed graph, the conditions for the starting point are as follows:\n\n<ul style=\"list-style-type: disc; padding-left: 1em;\">\n<li style=\"margin: 1em 0;\">\nIf exactly one vertex has one more outgoing edge than incoming edges (this will be the start of the path), exactly one vertex has one more incoming edge than outgoing edges (this will be the end of the path), and all other vertices have an equal number of incoming and outgoing edges.\n</li>\n<li style=\"margin: 1em 0;\">\nIf all vertices have an equal number of incoming and outgoing edges (forming an Eulerian Circuit), the algorithm can start from <strong>any vertex</strong>.\n</li>\n</ul>'),(6,'Kosaraju Algorithm - Strongly Connected Components','kosaraju-scc','async function algorithm({\n  graphRef,\n  tutorialRef,\n  waitOnClick,\n  nodes,\n  edges,\n  adjacency,\n  selectedNode,\n}) {\n  _ = this._\n\n  for (const [source, neighbours] of Object.entries(adjacency)) {\n    adjacency[source] = neighbours.map((val) => val.nodeId);\n  }\n\n  let visited = {};\n  const order = [];\n  const components = [];\n\n  async function dfs1(v, graph, order) {\n    visited[v] = true;\n\n    graphRef.current?.markNode({ nodeId: v });\n    tutorialRef.current?.addTutorialStep({\n      description: `Scouting Node ${v}: Let\'s see where these one-way streets lead and who\'s connected to whom.`,\n      variables: {\n        node: v,\n        neighbours: [...graph[v]],\n        order: [...order],\n      },\n      node: { nodeId: v },\n    });\n    await waitOnClick();\n\n    for (const u of graph[v]) {\n      if (!visited[u]) {\n        graphRef.current?.markEdge({\n          sourceId: v,\n          destinationId: u,\n          directed: true,\n        });\n        tutorialRef.current?.addTutorialStep({\n          description: `Taking the path from Node ${v} to Node ${u}. We\'re mapping out the connections to find the potential gateways of this city.`,\n          variables: {\n            node: v,\n            neighbours: [...graph[v]],\n            order: [...order],\n          },\n          edge: { sourceId: v, destinationId: u, directed: true },\n        });\n        await waitOnClick();\n\n        await dfs1(u, graph, order);\n      }\n    }\n\n    order.push(v);\n\n    tutorialRef.current?.addTutorialStep({\n      description: `Finished scouting Node ${v}. Adding it to our order list - this node is a key piece of the puzzle for our reverse search later!`,\n      variables: {\n        node: v,\n        neighbours: [...graph[v]],\n        order: [...order],\n      },\n    });\n    await waitOnClick();\n  }\n\n  async function dfs2(v, graph, component) {\n    visited[v] = true;\n\n    graphRef.current?.markNode({ nodeId: v });\n    tutorialRef.current?.addTutorialStep({\n      description: `Starting the reverse search at Node ${v}! Because we\'re moving against the original traffic, anyone we reach now is officially part of this node\'s Secret Society.`,\n      variables: {\n        node: v,\n        neighbours: [...graph[v]],\n        order: [...order],\n        component: [...component],\n        components: _.cloneDeep(components),\n      },\n      node: { nodeId: v },\n    });\n    await waitOnClick();\n\n    for (const u of graph[v]) {\n      if (!visited[u]) {\n        graphRef.current?.markEdge({\n          sourceId: v,\n          destinationId: u,\n          directed: true,\n        });\n        tutorialRef.current?.addTutorialStep({\n          description: `Following the reversed arrow from Node ${v} to Node ${u}. Since we can reach them even with the signs flipped, we\'ve proven they belong to the same Secret Society!`,\n          variables: {\n            node: v,\n            neighbours: [...graph[v]],\n            order: [...order],\n            component: [...component],\n            components: _.cloneDeep(components),\n          },\n          edge: { sourceId: v, destinationId: u, directed: true },\n        });\n        await waitOnClick();\n\n        await dfs2(u, graph, component);\n      }\n    }\n\n    component.push(v);\n\n    tutorialRef.current?.addTutorialStep({\n      description: `We\'ve confirmed the connection! We\'re adding Node ${v} to our current component. Since we reached it through the reversed arrows, it\'s officially part of this strongly connected group.`,\n      variables: {\n        node: v,\n        neighbours: [...graph[v]],\n        order: [...order],\n        component: [...component],\n        components: _.cloneDeep(components),\n      },\n    });\n    await waitOnClick();\n  }\n\n  const selectedNodeIndex = nodes.findIndex((node) => node.id === selectedNode)\n  \n  for (const node of [nodes[selectedNodeIndex], ...nodes]) {\n    if (!visited[node.id]) await dfs1(node.id, adjacency, order);\n  }\n\n  const adj_rev = {};\n\n  for (const node of nodes) {\n    adj_rev[node.id] = [];\n  }\n\n  for (const v of nodes) {\n    for (const u of adjacency[v.id]) {\n      adj_rev[u].push(v.id);\n    }\n  }\n\n  tutorialRef.current?.addTutorialStep({\n    description: `We\'re flipping every one-way sign in the city! By reversing all the arrows, we can now test if the paths we found earlier work in both directions, revealing the hidden loops between nodes.`,\n    transpose: true,\n    prevMarkings: graphRef.current?.getMarkings(),\n    nextMarkings: graphRef.current?.getDefaultMarkings(),\n  });\n  graphRef.current?.resetMarks();\n  graphRef.current?.transpose();\n\n  await waitOnClick();\n\n  visited = {};\n\n  while (order.length) {\n    const v = order.pop() ?? \"\";\n\n    tutorialRef.current?.addTutorialStep({\n      description: `We\'re taking the last node added to our Order List - this is our top priority! If it hasn\'t been grouped yet, we\'ll start a new search from here to uncover its entire Secret Society.`,\n      variables: {\n        node: v,\n        neighbours: [...adj_rev[v]],\n        order: [...order],\n        component: [],\n        components: _.cloneDeep(components),\n      },\n    });\n    await waitOnClick();\n\n    if (!visited[v]) {\n      const component = [];\n      await dfs2(v, adj_rev, component);\n      components.push(component);\n\n      tutorialRef.current?.addTutorialStep({\n        description: `Case closed! The algorithm has successfully identified a new Secret Society: (${component.join(\",\")}). Every member in this group is perfectly connected to one another!`,\n        variables: {\n          node: v,\n          neighbours: [...adj_rev[v]],\n          order: [...order],\n          component: [...component],\n          components: _.cloneDeep(components),\n        },\n      });\n      await waitOnClick();\n    }\n  }\n}\n\nreturn algorithm;\n','{\"variables\": {\"node\": \"\", \"order\": [], \"components\": [], \"neighbours\": []}, \"buttonText\": \"Start\", \"description\": \"The Kosaraju algorithm is a two-phase investigation designed to find \'Secret Societies\' (Strongly Connected Components) where every member can reach every other member through one-way streets. First, we conduct a global reconnaissance (DFS) to see which nodes are the ultimate gateways, ranking them by when we finish exploring them. Then, we flip every one-way sign in the city and start a second search in the order of our ranking. If we can still reach a group of nodes in this reversed world, it proves they are all part of a perfectly looped community where round trips are always possible.\"}','procedure Kosaraju(G):\n    S = empty stack\n    visited = empty set\n\n    # Step 1: DFS on original graph to fill stack\n    for each node in G:\n        if node not in visited:\n            DFS1(node)\n\n    # Step 2: Transpose the graph\n    GT = transpose(G)\n\n    # Step 3: DFS on transposed graph in stack order\n    visited = empty set\n    SCCs = empty list\n\n    while S not empty:\n        node = S.pop()\n        if node not in visited:\n            component = empty list\n            DFS2(node, component)\n            SCCs.append(component)\n\n    return SCCs\n\n\nprocedure DFS1(node):\n    visited.add(node)\n    for each neighbour in neighbours(node):\n        if neighbour not in visited:\n            DFS1(neighbour)\n    S.push(node)\n\n\nprocedure DFS2(node, component):\n    visited.add(node)\n    component.append(node)\n    for each neighbour in neighbours(node, in GT):\n        if neighbour not in visited:\n            DFS2(neighbour, component)\n\n\nfunction transpose(G):\n    GT = new graph\n    for each (u, v) in G.edges:\n        add edge (v, u) to GT\n    return GT','[{\"id\": \"1\"}, {\"id\": \"2\"}, {\"id\": \"3\"}, {\"id\": \"4\"}, {\"id\": \"5\"}, {\"id\": \"6\"}]','[{\"source\": {\"id\": \"2\"}, \"target\": {\"id\": \"1\"}, \"directed\": true}, {\"source\": {\"id\": \"1\"}, \"target\": {\"id\": \"3\"}, \"directed\": true}, {\"source\": {\"id\": \"2\"}, \"target\": {\"id\": \"4\"}, \"directed\": true}, {\"source\": {\"id\": \"3\"}, \"target\": {\"id\": \"5\"}, \"directed\": true}, {\"source\": {\"id\": \"5\"}, \"target\": {\"id\": \"6\"}, \"directed\": true}, {\"source\": {\"id\": \"5\"}, \"target\": {\"id\": \"2\"}, \"directed\": true}]','function reset({graphRef, tutorialRef}) {\n    graphRef.current?.transpose()\n}\n\nreturn reset',_binary '','');
